section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/dr-drill-scenario-library.json",
  "type": "object",
  "required": [
    "library_version",
    "scenarios",
    "rotation_calendar",
    "post_mortem_template_path",
    "min_scenarios"
  ],
  "properties": {
    "library_version": {
      "type": "string",
      "description": "string (semver)"
    },
    "scenarios": {
      "type": "array",
      "description": "array (each {id, name, declaration_criteria, runbook_path, restore_validation, success_criteria, last_run_date, owner})"
    },
    "rotation_calendar": {
      "type": "array",
      "description": "array (each {quarter, scenario_id})"
    },
    "post_mortem_template_path": {
      "type": "string",
      "description": "string"
    },
    "min_scenarios": {
      "type": "integer",
      "description": "integer (>=6)"
    }
  }
}

example.code:
{
  "library_version": "1.0.0",
  "scenarios": [
    {
      "id": "sc-01-region-loss",
      "name": "Primary region offline",
      "declaration_criteria": "AWS region status page red >15min",
      "runbook_path": "runbooks/dr/sc-01.md",
      "restore_validation": "smoke test + data-integrity hash check",
      "success_criteria": "RTO <60min RPO <5min",
      "last_run_date": "2026-02-15",
      "owner": "platform-team"
    },
    {
      "id": "sc-02-db-corruption",
      "name": "DB logical corruption",
      "declaration_criteria": "row checksum mismatch >0.1%",
      "runbook_path": "runbooks/dr/sc-02.md",
      "restore_validation": "point-in-time restore + integrity check",
      "success_criteria": "data restored to T-1h",
      "last_run_date": "2025-11-10",
      "owner": "data-team"
    }
  ],
  "rotation_calendar": [
    {
      "quarter": "2026-Q3",
      "scenario_id": "sc-04-identity-provider-out"
    }
  ],
  "post_mortem_template_path": "templates/postmortem.md",
  "min_scenarios": 6
}
